INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (94, NULL, NULL, NULL, '2025-11-07 15:28:50.871489', '2025-11-07 15:28:50.871540', 0, 20, 'deepseek-chat', 'assistant', NULL, '你的消息看起来可能包含中文拼音或随机的输入。如果你此刻感到困惑、有压力，或者只是想随便打些字——没关系，我在这里陪着你。如果你愿意，可以试着用一个词或简单的话描述你的心情，或者告诉我发生了什么。无论你想表达什么，我都会耐心倾听，也会尽力理解。你并不孤单，慢慢来。🌼', 1, NULL, NULL, NULL, NULL);
