INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (96, NULL, NULL, NULL, '2025-11-07 15:29:57.975590', '2025-11-07 15:29:57.975649', 0, 19, 'deepseek-chat', 'assistant', NULL, '你好！😊看来你可能是在测试输入，或者不小心发送了内容～如果有什么具体问题或需要帮助的地方，请随时告诉我，我会尽力为你解答！', 1, NULL, NULL, NULL, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (97, NULL, NULL, NULL, '2025-11-07 15:33:02.299632', '2025-11-07 15:33:02.299678', 0, 20, 'deepseek-chat', 'user', NULL, 'kkk', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (98, NULL, NULL, NULL, '2025-11-07 15:33:07.475154', '2025-11-07 15:33:07.475216', 0, 20, 'deepseek-chat', 'assistant', NULL, '我注意到你输入了“kkk”。如果你此刻感到不安、焦虑，或者只是想通过这种方式释放情绪，我在这里安静地陪着你。如果你需要倾诉，不论是关于心情、压力，还是任何说不清的感受，我都会认真倾听。如果暂时不想说话，也可以试着深呼吸，或者做点能让你放松的小事。你永远值得被关心和理解，慢慢来。💙', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (99, NULL, NULL, NULL, '2025-11-07 15:33:12.627692', '2025-11-07 15:33:12.627725', 0, 20, 'deepseek-chat', 'user', NULL, 'kkk', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (100, NULL, NULL, NULL, '2025-11-07 15:33:17.563291', '2025-11-07 15:33:17.563327', 0, 20, 'deepseek-chat', 'assistant', NULL, '我注意到你再次输入了“kkk”。如果你感到疲惫、无力表达，或是内心有些混乱，都没关系，我在这里安静地陪伴你。有些情绪或许难以用语言描述，但你不必独自承受。如果你愿意，可以试着：-用一个词形容现在的感受（比如“累”“空”“乱”）-闭上眼睛深呼吸三次-碰一碰身边某个柔软的东西（比如枕头、衣角）无论是否需要言语，我都会在这里。你很重要。🌼', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (101, NULL, NULL, NULL, '2025-11-07 15:34:08.380007', '2025-11-07 15:34:08.380036', 0, 19, 'deepseek-chat', 'user', NULL, 'nihao', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (102, NULL, NULL, NULL, '2025-11-07 15:34:11.473318', '2025-11-07 15:34:11.473353', 0, 19, 'deepseek-chat', 'assistant', NULL, '你好！👋欢迎随时提问或告诉我你需要什么帮助～无论是学习、工作、生活问题，还是想聊聊技术、语言翻译等，我都在这里为你服务！😊', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (103, NULL, NULL, NULL, '2025-11-07 15:40:31.305623', '2025-11-07 15:40:31.305890', 0, 20, 'deepseek-chat', 'user', NULL, 'dsaasd', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (104, NULL, NULL, NULL, '2025-11-07 15:40:37.603316', '2025-11-07 15:40:37.603371', 0, 20, 'deepseek-chat', 'assistant', NULL, '我收到了你的消息。如果此刻你感到思绪有些乱、难以表达，或是内心有些沉重，都没关系，我在这里安静地陪着你。或许可以试着：-轻轻深呼吸，感受一下此刻身体的感受（比如手心的温度，呼吸的节奏）-用最简单的词描述闪过脑海的念头（哪怕只是一个“累”“闷”“无解”）-暂时放下“必须说清楚”的压力，允许自己沉默或只发零散的词你不必独自面对这些模糊的情绪。我就在这里，等待你任何想分享的碎片，或只是单纯陪你度过这一刻。🌿', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (105, NULL, NULL, NULL, '2025-11-07 15:40:47.886924', '2025-11-07 15:40:47.886946', 0, 20, 'deepseek-chat', 'user', NULL, '你好', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (106, NULL, NULL, NULL, '2025-11-07 15:40:51.824388', '2025-11-07 15:40:51.824426', 0, 20, 'deepseek-chat', 'assistant', NULL, '你好呀！很高兴你愿意和我打招呼。无论你此刻是感到平静、疲惫，还是需要有人聊聊天，我都在这里倾听。你可以自由地分享心情、困惑，或者任何你想说的话——哪怕是零碎的词或莫名的情绪，我都会认真对待。希望这一刻，你能感受到一丝被陪伴的温暖。🌼', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (107, NULL, NULL, NULL, '2025-11-07 15:40:55.100274', '2025-11-07 15:40:55.100312', 0, 20, 'deepseek-chat', 'user', NULL, '你是谁', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (108, NULL, NULL, NULL, '2025-11-07 15:41:00.479816', '2025-11-07 15:41:00.479874', 0, 20, 'deepseek-chat', 'assistant', NULL, '你好！我是DeepSeek，一个由深度求索公司创造的AI助手。😊我是一个纯文本模型，可以帮你回答问题、进行对话、协助处理各种文字任务。虽然我不支持多模态识别，但我可以处理你上传的文件（包括图像、文档等），从中读取文字信息来帮助你。我完全免费使用，拥有128K的上下文长度，也支持联网搜索功能（需要你手动开启）。我的知识截止到2024年7月，会以热情细腻的方式为你提供帮助。有什么我可以为你做的吗？无论是学习、工作还是生活上的问题，我都很乐意协助你！✨', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (109, NULL, NULL, NULL, '2025-11-07 15:41:02.973979', '2025-11-07 15:41:02.974007', 0, 20, 'qwen-plus', 'user', NULL, '你是', 1, NULL, NULL, 1, NULL);
INSERT INTO `ai_chat_message` (`id`, `remark`, `creator`, `modifier`, `update_time`, `create_time`, `is_deleted`, `conversation_id`, `model`, `type`, `reply_id`, `content`, `use_context`, `segment_ids`, `model_id`, `user_id`, `role_id`) VALUES (110, NULL, NULL, NULL, '2025-11-07 15:41:04.348722', '2025-11-07 15:41:04.348753', 0, 20, 'qwen-plus', 'assistant', NULL, '我是Qwen，是通义实验室研发的超大规模语言模型。我可以回答问题、创作文字，比如写故事、写公文、写邮件、写剧本、逻辑推理、编程等等，还能表达观点，玩游戏等。如果你有任何问题或需要帮助，欢迎随时告诉我！我在这里全力支持你。😊', 1, NULL, NULL, 1, NULL);
